import React, { useContext, useEffect } from 'react';
import { Container } from 'react-bootstrap'; 
// Importamos los contextos para mantener la estructura y evitar errores de hook
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes dependientes
import SearchBox from './SearchBox';

// NOTA: Mantenemos todas las dependencias y hooks para que el componente no falle.
const Header = () => {
  // CRÍTICO: Mantener los hooks de contexto, aunque no se usen sus valores, para evitar un crash
  const { loading: authLoading } = useContext(AuthContext); 
  const { loading: settingsLoading } = useContext(SettingsContext);
  
  // Mantenemos este efecto para que las variables CSS funcionen, si es necesario.
  const { settings } = useContext(SettingsContext);
  useEffect(() => {
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  // Si está cargando, podemos devolver null o un esqueleto (asumimos que ya no lo necesitamos, pero si se cae, descomentamos el HeaderSkeleton)
  // const isLoading = authLoading || settingsLoading;
  // if (isLoading) { return <HeaderSkeleton />; }

  return (
    // Clase CRÍTICA: rounded-b-xl para el redondeo inferior.
    <header 
      className="w-full sticky top-0 z-50 transition-all duration-300 shadow-md rounded-b-xl"
      style={{ backgroundColor: 'var(--brand-dark)' }} 
    >
      <Container className="py-3"> 
        
        {/* Contenedor principal con flex para centrar la barra de búsqueda */}
        {/* Usamos justify-center para centrar el contenido horizontalmente */}
        <div className="flex justify-center items-center w-full"> 
          
          {/* Barra de búsqueda: Centrada y con ancho máximo (max-w-lg) */}
          {/* mx-auto centra el div dentro del flex container si no ocupa todo el espacio */}
          <div className="w-full max-w-lg mx-auto">
            <SearchBox /> 
          </div>
          
          {/* NOTA: Eliminamos o comentamos aquí los elementos de Logo, Carrito y Usuario
             para cumplir la petición de "solo deja la seachbox". */}
        </div>
        
        {/* Eliminamos el buscador de móvil por ahora, ya que la petición es que solo haya uno. */}
        
      </Container>
    </header>
  );
};

export default Header;
